import Foundation
import SoundAnalysis
import AVFoundation
import Combine

class ClassifierViewModel: NSObject, ObservableObject, SNResultsObserving {
    @Published var topClassification: String = "Listening..."
    @Published var confidence: Double = 0.0
    @Published var isListening = false
    @Published var errorMessage: String?

    private let audioEngine = AVAudioEngine()
    private var analyzer: SNAudioStreamAnalyzer?

    func startListening() {
        do {
            let session = AVAudioSession.sharedInstance()
            try session.setCategory(.record, mode: .measurement)
            try session.setActive(true)

            let inputNode = audioEngine.inputNode
            let format = inputNode.outputFormat(forBus: 0)

            analyzer = SNAudioStreamAnalyzer(format: format)
            let request = try SNClassifySoundRequest(classifierIdentifier: .version1)
            try analyzer?.add(request, withObserver: self)

            inputNode.installTap(onBus: 0, bufferSize: 8192, format: format) { [weak self] buffer, time in
                self?.analyzer?.analyze(buffer, atAudioFramePosition: time.sampleTime)
            }

            try audioEngine.start()
            isListening = true
        } catch {
            errorMessage = error.localizedDescription
        }
    }

    func stopListening() {
        audioEngine.stop()
        audioEngine.inputNode.removeTap(onBus: 0)
        analyzer = nil
        isListening = false
    }

    func request(_ request: SNRequest, didProduce result: SNResult) {
        guard let classification = result as? SNClassificationResult,
              let top = classification.classifications.first,
              top.confidence > 0.3 else { return }
        DispatchQueue.main.async {
            self.topClassification = top.identifier.replacingOccurrences(of: "_", with: " ").capitalized
            self.confidence = top.confidence
        }
    }

    func request(_ request: SNRequest, didFailWithError error: Error) {
        DispatchQueue.main.async {
            self.errorMessage = error.localizedDescription
            self.isListening = false
        }
    }
}
